#include <math.h>
#include <stdio.h>
#include <stdlib.h>

#include "avilib.h"
#include "define.c"

void kernel(public_struct public, private_struct private){

	int ei_new;
	fp* d_in;
	int rot_row;
	int rot_col;
	int in2_rowlow;
	int in2_collow;
	int ic;
	int jc;
	int jp1;
	int ja1, ja2;
	int ip1;
	int ia1, ia2;
	int ja, jb;
	int ia, ib;
	fp s;
	int i;
	int j;
	int row;
	int col;
	int ori_row;
	int ori_col;
	int position;
	fp sum;
	int pos_ori;
	fp temp;
	fp temp2;
	int location;
	int cent;
	int tMask_row; 
	int tMask_col;
	fp largest_value_current = 0;
	fp largest_value = 0;
	int largest_coordinate_current = 0;
	int largest_coordinate = 0;
	fp fin_max_val = 0;
	int fin_max_coo = 0;
	int largest_row;
	int largest_col;
	int offset_row;
	int offset_col;
	fp in_final_sum;
	fp in_sqr_final_sum;
	fp mean;
	fp mean_sqr;
	fp variance;
	fp deviation;
	fp denomT;
	int pointer;
	int ori_pointer;
	int loc_pointer;

	if(public.frame_no == 0){

		pointer = private.point_no*public.frames+public.frame_no;
		private.d_tRowLoc[pointer] = private.d_Row[private.point_no];
		private.d_tColLoc[pointer] = private.d_Col[private.point_no];

		d_in = &private.d_T[private.in_pointer];

		for(col=0; col<public.in_cols; col++){
			for(row=0; row<public.in_cols; row++){

				ori_row = private.d_Row[private.point_no] - 25 + row - 1;
				ori_col = private.d_Col[private.point_no] - 25 + col - 1;
				ori_pointer = ori_col*public.frame_rows+ori_row;

				d_in[col*public.in_cols+row] = public.d_frame[ori_pointer];

			}
		}

	}

	if(public.frame_no != 0){

		in2_rowlow = private.d_Row[private.point_no] - public.sSize;							
		in2_collow = private.d_Col[private.point_no] - public.sSize;

		for(col=0; col<public.in2_cols; col++){
			for(row=0; row<public.in2_rows; row++){

				ori_row = row + in2_rowlow - 1;
				ori_col = col + in2_collow - 1;
				temp = public.d_frame[ori_col*public.frame_rows+ori_row];
				private.d_in2[col*public.in2_rows+row] = temp;
				private.d_in2_sqr[col*public.in2_rows+row] = temp*temp;

			}
		}

		d_in = &private.d_T[private.in_pointer];

		for(col=0; col<public.in_cols; col++){
			for(row=0; row<public.in_cols; row++){

				rot_row = (public.in_cols-1) - row;
				rot_col = (public.in_cols-1) - col;
				pointer = rot_col*public.in_cols+rot_row;

				temp = d_in[pointer];
				private.d_in_mod[col*public.in_cols+row] = temp;
				private.d_in_sqr[pointer] = temp * temp;

			}
		}

		in_final_sum = 0;
		for(i = 0; i<public.in_elem; i++){
			in_final_sum = in_final_sum + d_in[i];
		}

		in_sqr_final_sum = 0;
		for(i = 0; i<public.in_elem; i++){
			in_sqr_final_sum = in_sqr_final_sum + private.d_in_sqr[i];
		}

		mean = in_final_sum / public.in_elem;													
		mean_sqr = mean * mean;
		variance  = (in_sqr_final_sum / public.in_elem) - mean_sqr;							
		deviation = sqrt(variance);																

		denomT = sqrt((fp)(public.in_elem-1))*deviation;

		for(col=1; col<=public.conv_cols; col++){

			j = col + public.joffset;
			jp1 = j + 1;
			if(public.in2_cols < jp1){
				ja1 = jp1 - public.in2_cols;
			}
			else{
				ja1 = 1;
			}
			if(public.in_cols < j){
				ja2 = public.in_cols;
			}
			else{
				ja2 = j;
			}

			for(row=1; row<=public.conv_rows; row++){

				i = row + public.ioffset;
				ip1 = i + 1;

				if(public.in2_rows < ip1){
					ia1 = ip1 - public.in2_rows;
				}
				else{
					ia1 = 1;
				}
				if(public.in_rows < i){
					ia2 = public.in_rows;
				}
				else{
					ia2 = i;
				}

				s = 0;

				for(ja=ja1; ja<=ja2; ja++){
					jb = jp1 - ja;
					for(ia=ia1; ia<=ia2; ia++){
						ib = ip1 - ia;
						s = s + private.d_in_mod[public.in_cols*(ja-1)+ia-1] * private.d_in2[public.in2_rows*(jb-1)+ib-1];
					}
				}

				private.d_conv[(col-1)*public.conv_rows+(row-1)] = s;

			}
		}

		for(col=0; col<public.in2_pad_cumv_cols; col++){
			for(row=0; row<public.in2_pad_cumv_rows; row++){

				if(	row > (public.in2_pad_add_rows-1) &&														
					row < (public.in2_pad_add_rows+public.in2_rows) && 
					col > (public.in2_pad_add_cols-1) && 
					col < (public.in2_pad_add_cols+public.in2_cols)){
					ori_row = row - public.in2_pad_add_rows;
					ori_col = col - public.in2_pad_add_cols;
					private.d_in2_pad_cumv[col*public.in2_pad_cumv_rows+row] = private.d_in2[ori_col*public.in2_rows+ori_row];
				}
				else{																			
					private.d_in2_pad_cumv[col*public.in2_pad_cumv_rows+row] = 0;
				}

			}
		}

		for(ei_new = 0; ei_new < public.in2_pad_cumv_cols; ei_new++){

			pos_ori = ei_new*public.in2_pad_cumv_rows;

			sum = 0;
			for(position = pos_ori; position < pos_ori+public.in2_pad_cumv_rows; position = position + 1){
				private.d_in2_pad_cumv[position] = private.d_in2_pad_cumv[position] + sum;
				sum = private.d_in2_pad_cumv[position];
			}

		}

		for(col=0; col<public.in2_pad_cumv_sel_cols; col++){
			for(row=0; row<public.in2_pad_cumv_sel_rows; row++){

				ori_row = row + public.in2_pad_cumv_sel_rowlow - 1;
				ori_col = col + public.in2_pad_cumv_sel_collow - 1;
				private.d_in2_pad_cumv_sel[col*public.in2_pad_cumv_sel_rows+row] = private.d_in2_pad_cumv[ori_col*public.in2_pad_cumv_rows+ori_row];

			}
		}

		for(col=0; col<public.in2_sub_cumh_cols; col++){
			for(row=0; row<public.in2_sub_cumh_rows; row++){

				ori_row = row + public.in2_pad_cumv_sel2_rowlow - 1;
				ori_col = col + public.in2_pad_cumv_sel2_collow - 1;
				private.d_in2_sub_cumh[col*public.in2_sub_cumh_rows+row] = private.d_in2_pad_cumv[ori_col*public.in2_pad_cumv_rows+ori_row];

			}
		}

		for(ei_new = 0; ei_new < public.in2_sub_cumh_elem; ei_new++){

			private.d_in2_sub_cumh[ei_new] = private.d_in2_pad_cumv_sel[ei_new] - private.d_in2_sub_cumh[ei_new];

		}

		for(ei_new = 0; ei_new < public.in2_sub_cumh_rows; ei_new++){

			pos_ori = ei_new;

			sum = 0;
			for(position = pos_ori; position < pos_ori+public.in2_sub_cumh_elem; position = position + public.in2_sub_cumh_rows){
				private.d_in2_sub_cumh[position] = private.d_in2_sub_cumh[position] + sum;
				sum = private.d_in2_sub_cumh[position];
			}

		}

		for(col=0; col<public.in2_sub_cumh_sel_cols; col++){
			for(row=0; row<public.in2_sub_cumh_sel_rows; row++){

				ori_row = row + public.in2_sub_cumh_sel_rowlow - 1;
				ori_col = col + public.in2_sub_cumh_sel_collow - 1;
				private.d_in2_sub_cumh_sel[col*public.in2_sub_cumh_sel_rows+row] = private.d_in2_sub_cumh[ori_col*public.in2_sub_cumh_rows+ori_row];

			}
		}

		for(col=0; col<public.in2_sub2_cols; col++){
			for(row=0; row<public.in2_sub2_rows; row++){

				ori_row = row + public.in2_sub_cumh_sel2_rowlow - 1;
				ori_col = col + public.in2_sub_cumh_sel2_collow - 1;
				private.d_in2_sqr_sub2[col*public.in2_sub2_rows+row] = private.d_in2_sub_cumh[ori_col*public.in2_sub_cumh_rows+ori_row];

			}
		}

		for(ei_new = 0; ei_new < public.in2_sub2_elem; ei_new++){

			private.d_in2_sqr_sub2[ei_new] = private.d_in2_sub_cumh_sel[ei_new] - private.d_in2_sqr_sub2[ei_new];

		}

		for(ei_new = 0; ei_new < public.in2_sub2_elem; ei_new++){

			temp = private.d_in2_sub2[ei_new];
			temp2 = private.d_in2_sqr_sub2[ei_new] - (temp * temp / public.in_elem);
			if(temp2 < 0){
				temp2 = 0;
			}
			private.d_in2_sqr_sub2[ei_new] = sqrt(temp2);

		}

		for(ei_new = 0; ei_new < public.in_sqr_elem; ei_new++){

			temp = d_in[ei_new];
			private.d_in_sqr[ei_new] = temp * temp;

		}

		for(ei_new = 0; ei_new < public.in_cols; ei_new++){

			sum = 0;
			for(i = 0; i < public.in_cols; i++){

				sum = sum + d_in[ei_new*public.in_cols+i];

			}
			private.in_partial_sum[ei_new] = sum;

		}

		for(ei_new = 0; ei_new < public.in_sqr_rows; ei_new++){

			sum = 0;
			for(i = 0; i < public.in_sqr_cols; i++){

				sum = sum + private.d_in_sqr[ei_new+public.in_sqr_rows*i];

			}
			private.in_sqr_partial_sum[ei_new] = sum;

		}

		if(0 == 0){

			in_final_sum = 0;
			for(i = 0; i<public.in_cols; i++){
				in_final_sum = in_final_sum + private.in_partial_sum[i];
			}

		}

		if(1 == 1){

			in_sqr_final_sum = 0;
			for(i = 0; i<public.in_sqr_cols; i++){
				in_sqr_final_sum = in_sqr_final_sum + private.in_sqr_partial_sum[i];
			}

		}

		mean = in_final_sum / public.in_elem;													
		mean_sqr = mean * mean;
		variance  = (in_sqr_final_sum / public.in_elem) - mean_sqr;							
		deviation = sqrt(variance);																

		denomT = sqrt((fp)(public.in_elem-1))*deviation;

		for(ei_new = 0; ei_new < public.in2_sub2_elem; ei_new++){

			private.d_in2_sqr_sub2[ei_new] = private.d_in2_sqr_sub2[ei_new] * denomT;

		}

		for(ei_new = 0; ei_new < public.conv_elem; ei_new++){

			private.d_conv[ei_new] = private.d_conv[ei_new] - private.d_in2_sub2[ei_new] * in_final_sum / public.in_elem;

		}

		for(ei_new = 0; ei_new < public.in2_sub2_elem; ei_new++){

			private.d_in2_sqr_sub2[ei_new] = private.d_conv[ei_new] / private.d_in2_sqr_sub2[ei_new];

		}

		cent = public.sSize + public.tSize + 1;
		if(public.frame_no == 0){
			tMask_row = cent + private.d_Row[private.point_no] - private.d_Row[private.point_no] - 1;
			tMask_col = cent + private.d_Col[private.point_no] - private.d_Col[private.point_no] - 1;
		}
		else{
			pointer = public.frame_no-1+private.point_no*public.frames;
			tMask_row = cent + private.d_tRowLoc[pointer] - private.d_Row[private.point_no] - 1;
			tMask_col = cent + private.d_tColLoc[pointer] - private.d_Col[private.point_no] - 1;
		}

		for(ei_new = 0; ei_new < public.tMask_elem; ei_new++){
			private.d_tMask[ei_new] = 0;
		}
		private.d_tMask[tMask_col*public.tMask_rows + tMask_row] = 1;

		for(col=1; col<=public.mask_conv_cols; col++){

			j = col + public.mask_conv_joffset;
			jp1 = j + 1;
			if(public.mask_cols < jp1){
				ja1 = jp1 - public.mask_cols;
			}
			else{
				ja1 = 1;
			}
			if(public.tMask_cols < j){
				ja2 = public.tMask_cols;
			}
			else{
				ja2 = j;
			}

			for(row=1; row<=public.mask_conv_rows; row++){

				i = row + public.mask_conv_ioffset;
				ip1 = i + 1;

				if(public.mask_rows < ip1){
					ia1 = ip1 - public.mask_rows;
				}
				else{
					ia1 = 1;
				}
				if(public.tMask_rows < i){
					ia2 = public.tMask_rows;
				}
				else{
					ia2 = i;
				}

				s = 0;

				for(ja=ja1; ja<=ja2; ja++){
					jb = jp1 - ja;
					for(ia=ia1; ia<=ia2; ia++){
						ib = ip1 - ia;
						s = s + private.d_tMask[public.tMask_rows*(ja-1)+ia-1] * 1;
					}
				}

				private.d_mask_conv[(col-1)*public.conv_rows+(row-1)] = private.d_in2_sqr_sub2[(col-1)*public.conv_rows+(row-1)] * s;

			}

		}

		fin_max_val = 0;
		fin_max_coo = 0;
		for(i=0; i<public.mask_conv_elem; i++){
			if(fabs(private.d_mask_conv[i])>fin_max_val){
				fin_max_val = fabs(private.d_mask_conv[i]);
				fin_max_coo = i;
			}
		}

		largest_row = (fin_max_coo+1) % public.mask_conv_rows - 1;											
		largest_col = (fin_max_coo+1) / public.mask_conv_rows;												
		if((fin_max_coo+1) % public.mask_conv_rows == 0){
			largest_row = public.mask_conv_rows - 1;
			largest_col = largest_col - 1;
		}

		largest_row = largest_row + 1;																	
		largest_col = largest_col + 1;																	
		offset_row = largest_row - public.in_cols - (public.sSize - public.tSize);
		offset_col = largest_col - public.in_cols - (public.sSize - public.tSize);
		pointer = private.point_no*public.frames+public.frame_no;
		private.d_tRowLoc[pointer] = private.d_Row[private.point_no] + offset_row;
		private.d_tColLoc[pointer] = private.d_Col[private.point_no] + offset_col;

	}

	if(public.frame_no != 0 && (public.frame_no)%10 == 0){

		loc_pointer = private.point_no*public.frames+public.frame_no;
		private.d_Row[private.point_no] = private.d_tRowLoc[loc_pointer];
		private.d_Col[private.point_no] = private.d_tColLoc[loc_pointer];

		d_in = &private.d_T[private.in_pointer];

		for(col=0; col<public.in_cols; col++){
			for(row=0; row<public.in_cols; row++){

				ori_row = private.d_Row[private.point_no] - 25 + row - 1;
				ori_col = private.d_Col[private.point_no] - 25 + col - 1;
				ori_pointer = ori_col*public.frame_rows+ori_row;

				d_in[col*public.in_cols+row] = public.alpha*d_in[col*public.in_cols+row] + (1.00-public.alpha)*public.d_frame[ori_pointer];

			}
		}

	}

}
